/**
 * This method was created by a SmartGuide.
 */
public void loadBase ( ) {
/**
 * determine the upper-left corner of the base
 */
		int basePositionX = POSITION_0.x + xOffset();
		int basePositionY = POSITION_0.y;
/**
 * now instantiate the base with control of the graphics
 * immediately around it
 */
		Base base = new Base(baseGif, deadBaseGif, missileCommandScreen().graphics().create(basePositionX,basePositionY, 60, 50));
		base.imageObserver(missileCommandScreen());
/**
 * increase the xOffset as appropriate
 */
		xOffset(xOffset() + DISTANCE_AROUND_BASE);
/**
 * let the base know where it is located in the gameScreen
 * and then add it to the gameManager
 */
		base.location(basePositionX, basePositionY);
		missileCommandManager().addBase(base);
/**
 * incriment and tweak the xOffset
 */
		xOffset(xOffset() + DISTANCE_AROUND_BASE + 7);
}
/**
 * This method was created by a SmartGuide.
 */
public void loadThreeCities ( ) {
	int cityNumber = 0;
	while(cityNumber < 3){
/**
 * adjust the xOffSet as appropriate
 */
		xOffset(xOffset()+DISTANCE_BETWEEN_CITIES);
/**
 * determine the position of the city in question
 */		
		int cityPositionX = POSITION_0.x+xOffset();
		int cityPositionY = POSITION_0.y+YOFFSET_FROM_BASES_TO_CITIES;
/**
 * 	tell the city where it is located, then add it to the
 *  gameManager
 */	
 		City city = new City(cityGif, deadCityGif, missileCommandScreen().getGraphics().create(cityPositionX,cityPositionY, 25, 25));
		city.imageObserver(missileCommandScreen());
		city.location(cityPositionX, cityPositionY);
		missileCommandManager().addCity(city);
		cityNumber ++; 
	}	
	xOffset(xOffset()+DISTANCE_BETWEEN_CITIES);
}
