/**
 * This method was created by a SmartGuide.
 */
public void startGame() {
	missileCommandScreen().manage(missileCommandManager());
	missileCommandManager().scoreBoardI(scoreBoardI());
	xOffset(0);
	loadBase();
	loadThreeCities();
	loadBase();
	loadThreeCities();
	loadBase();
	Sky s = new Sky();
	s.missileCommandManager(missileCommandManager());
  missileCommandManager().staticManagerI().addStaticI(s);

/**
 * Now we will create the Level Manager, and begin the game in "stopped"
 * mode.
 */ 
	SmartMissileCommandLevelManager smclm = new SmartMissileCommandLevelManager();
	missileCommandManager().missileCommandLevelManager(smclm);
	smclm.missileCommandManager(missileCommandManager());
	smclm.dynamicManagerI(missileCommandManager().dynamicManagerI());
	missileCommandManager().addObserver(smclm);
	smclm.graphics(missileCommandScreen().graphics().create(90, 170, 280, 30));
	requestFocus();
	missileCommandManager().dynamicManagerI().thread(new Thread());
	missileCommandManager().endGame();}
